sql.where:
   	A.deviceIdx = B.id AND B.constructionIdx = C.id
		and A.deviceIdx = ${param.id}

  			and currentDateTime = #{param.date}


			and A.isdel = 0 


  			and ${param.searchField} like '%${param.searchWord}%'


  			and date(A.currentDateTime) >= #{param.startDate} and date(A.currentDateTime) <= #{param.endDate} 


  			and A.pileNo = #{param.pileNo} 


  			and A.location = #{param.location} 


  			and A.method like '%${param.method}%'

 	A.deviceIdx = B.id AND B.constructionIdx = C.id

			and ${param.id} = A.deviceIdx and A.isdel = 0 


			and ${param.searchField} like '%${param.searchWord}%'


			and date(A.currentDateTime) >= #{param.startDate} and date(A.currentDateTime) <= #{param.endDate} 


			and A.pileNo = #{param.pileNo} 


			and A.location = #{param.location} 


			and C.id = #{param.constructionIdx}  and A.isdel = 0

 	1=1

			and AA.machineNumber = #{param.machineNumber}


			and AA.currentDateTime = #{param.currentDateTime}


			and ${param.searchField} like '%${param.searchWord}%'


			and date(AA.currentDateTime) >= #{param.startDate} and date(AA.currentDateTime) <= #{param.endDate} 


			and AA.pileNo = #{param.pileNo} 


			and AA.location = #{param.location} 




					and AA.currentDateTime = curdate()


					and AA.currentDateTime = #{param.date}

mapper.select:
SELECT BB.cnt as duplicated, IFNULL(CC.cnt, 0) as totalDuplicated, ifnull(getZoneNameForSamsung(TRIM(AA.pileNo)), 'ept') as zone, AA.name , AA.longCalYn , AA.ubcYn , AA.lavelNo , AA.machineNumber , AA.id , AA.deviceIdx , AA.currentDateTime , AA.location , AA.pileNo , AA.pileStandard , AA.drillingDepth , AA.intrusionDepth , AA.balance , AA.connectLength , AA.managedStandard , AA.avgPenetrationValue , AA.totalPenetrationValue , AA.hammaT , AA.fallMeter , AA.pileType , AA.method , AA.totalConnectWidth , AA.ultimateBearingCapacity , AA.crossSection , AA.hammaEfficiency , AA.modulusElasticity , AA.createDate, AA.isDel , AA.isDuple , AA.bigo , AA.sprCol1 , AA.constructionIdx , AA.peOne , AA.peTwo , AA.peThree , AA.peFour , AA.peFive , AA.peSix , AA.peSeven , AA.peEight , AA.peNine , AA.peTen , AA.piOne , AA.piTwo , AA.piThree , AA.piFour , AA.piFive , AA.peLength FROM ( SELECT name , longCalYn , ubcYn , lavelNo , machineNumber , id , deviceIdx , currentDateTime , location , pileNo , pileStandard , drillingDepth , intrusionDepth , balance , connectLength , managedStandard , avgPenetrationValue , totalPenetrationValue , hammaT , fallMeter , pileType , method , totalConnectWidth , ultimateBearingCapacity , crossSection , hammaEfficiency , modulusElasticity , isDel, isDuple, role , IF(bigo = 'null','', bigo) as bigo , IF(sprCol1 = 'null','', sprCol1) as sprCol1 , createDate, constructionIdx, peOne, peTwo, peThree, peFour, peFive, peSix, peSeven, peEight, peNine, peTen , piOne, piTwo, piThree, piFour, piFive , peLength FROM ( SELECT C.name as name , C.longCalYn , C.ubcYn , B.lavelNo as lavelNo , B.machineNumber as machineNumber , A.id , A.deviceIdx , A.currentDateTime , A.location , A.pileNo , A.pileStandard , A.drillingDepth , A.intrusionDepth , A.balance , A.connectLength , A.managedStandard , A.avgPenetrationValue , A.totalPenetrationValue , A.hammaT , A.fallMeter , A.pileType , A.method , A.totalConnectWidth , A.ultimateBearingCapacity , A.crossSection , A.hammaEfficiency , A.modulusElasticity , A.isDel, A.isDuple, C.role , IF(A.bigo = 'null','', A.bigo) as bigo , IF(A.sprCol1 = 'null','', A.sprCol1) as sprCol1 , A.createDate , B.constructionIdx , (SELECT VALUE FROM TB_PENETRATION WHERE reportIdx = A.id LIMIT 0,1) as peOne, (SELECT VALUE FROM TB_PENETRATION WHERE reportIdx = A.id LIMIT 1,1) as peTwo, (SELECT VALUE FROM TB_PENETRATION WHERE reportIdx = A.id LIMIT 2,1) as peThree, (SELECT VALUE FROM TB_PENETRATION WHERE reportIdx = A.id LIMIT 3,1) as peFour, (SELECT VALUE FROM TB_PENETRATION WHERE reportIdx = A.id LIMIT 4,1) as peFive, (SELECT VALUE FROM TB_PENETRATION WHERE reportIdx = A.id LIMIT 5,1) as peSix, (SELECT VALUE FROM TB_PENETRATION WHERE reportIdx = A.id LIMIT 6,1) as peSeven, (SELECT VALUE FROM TB_PENETRATION WHERE reportIdx = A.id LIMIT 7,1) as peEight, (SELECT VALUE FROM TB_PENETRATION WHERE reportIdx = A.id LIMIT 8,1) as peNine, (SELECT VALUE FROM TB_PENETRATION WHERE reportIdx = A.id LIMIT 9,1) as peTen , ifnull((SELECT IF(VALUE = 0, '', VALUE) as VALUE FROM TB_PIECE WHERE reportIdx = A.id and name = "단본" ORDER BY TB_PIECE.id ASC LIMIT 0, 1 ),'') as piOne, ifnull((SELECT IF(VALUE = 0, '', VALUE) as VALUE FROM TB_PIECE WHERE reportIdx = A.id and name = "하단" ORDER BY TB_PIECE.id ASC LIMIT 0, 1 ),'') as piTwo, ifnull((SELECT IF(VALUE = 0, '', VALUE) as VALUE FROM TB_PIECE WHERE reportIdx = A.id and name = "중단" LIMIT 0,1),'') as piThree, ifnull((SELECT IF(VALUE = 0, '', VALUE) as VALUE FROM TB_PIECE WHERE reportIdx = A.id and name = "중단" LIMIT 1,1),'') as piFour, ifnull((SELECT IF(VALUE = 0, '', VALUE) as VALUE FROM TB_PIECE WHERE reportIdx = A.id and name = "상단" ORDER BY TB_PIECE.id ASC LIMIT 0, 1 ),'') as piFive, (SELECT SUM(CASE WHEN VALUE IS NULL THEN 0 ELSE 1 END) AS peLength FROM TB_PENETRATION WHERE reportIdx = A.id LIMIT 5) as peLength
FROM TB_REPORT A , TB_DEVICE B, TB_CONSTRUCTION C
ORDER BY A.createDate DESC ) as TB) AA LEFT OUTER JOIN (SELECT COUNT(*) as cnt, deviceIdx, pileNo, location FROM TB_REPORT WHERE deviceIdx = ${param.id} AND isDel = 0 GROUP BY deviceIdx, pileNo, location) BB ON AA.deviceIdx = BB.deviceIdx AND AA.pileNo = BB.pileNo AND AA.location = BB.location LEFT OUTER JOIN (SELECT COUNT(*) as cnt, pileNo, location FROM TB_REPORT WHERE deviceIdx = ${param.id} AND isDel = 0 GROUP BY pileNo, location) CC ON AA.pileNo = CC.pileNo AND AA.location = CC.location WHERE 1=1 ORDER BY AA.createDate DESC LIMIT #{pageSize} OFFSET #{startRow}

mapper.insert:
INSERT INTO TB_REPORT ( deviceIdx, currentDateTime, location, pileNo , pileStandard, drillingDepth , intrusionDepth, balance, connectLength, managedStandard, avgPenetrationValue, totalPenetrationValue, hammaT, fallMeter, pileType, method, totalConnectWidth, ultimateBearingCapacity, crossSection , hammaEfficiency , modulusElasticity
, bigo
, createDate ) VALUES ( #{deviceIdx}, #{currentDateTime}, #{location}, #{pileNo} , #{pileStandard}, #{drillingDepth} , #{intrusionDepth}, #{balance}, #{connectLength}, #{managedStandard}, #{avgPenetrationValue}, #{totalPenetrationValue}, #{hammaT}, #{fallMeter}, #{pileType}, #{method}, #{totalConnectWidth}, #{ultimateBearingCapacity} , #{crossSection} , #{hammaEfficiency} , #{modulusElasticity}
, #{bigo}
, now() )
SELECT LAST_INSERT_ID()

